class Solution {
public:
    string largestMerge(string word1, string word2) {
        string res;
        while (!word1.empty() && !word2.empty()) {
            if (word1 > word2) {
                res += word1[0];
                word1.erase(0, 1);
            } else {
                res += word2[0];
                word2.erase(0, 1);
            }
        }
        res += word1;
        res += word2;
        return res;
    }
};
